import{_ as a,o,c as i,an as t}from"./chunks/framework.DKgvuBLA.js";const m=JSON.parse('{"title":"Política de privacidad","description":"","frontmatter":{},"headers":[],"relativePath":"es/privacy-policy.md","filePath":"es/privacy-policy.md"}'),s={name:"es/privacy-policy.md"};function l(n,e,c,r,d,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="politica-de-privacidad" tabindex="-1">Política de privacidad <a class="header-anchor" href="#politica-de-privacidad" aria-label="Permalink to &quot;Política de privacidad&quot;">​</a></h1><p>Esta página explica cómo <code>particles.js.org</code> maneja los datos personales relacionados con los servicios de análisis y publicidad.</p><h2 id="alcance" tabindex="-1">Alcance <a class="header-anchor" href="#alcance" aria-label="Permalink to &quot;Alcance&quot;">​</a></h2><p>Esta política cubre el sitio web de documentos y las páginas relacionadas proporcionadas desde <code>particles.js.org</code>.</p><h2 id="datos-que-procesamos" tabindex="-1">Datos que procesamos <a class="header-anchor" href="#datos-que-procesamos" aria-label="Permalink to &quot;Datos que procesamos&quot;">​</a></h2><ul><li>Datos técnicos de navegación (metadatos derivados de IP, agente de usuario, referente, URL de página).</li><li>Eventos analíticos para tendencias de uso de documentación.</li><li>Eventos relacionados con la publicidad requeridos por Google AdSense cuando se otorga el consentimiento.</li></ul><h2 id="servicios-utilizados" tabindex="-1">Servicios utilizados <a class="header-anchor" href="#servicios-utilizados" aria-label="Permalink to &quot;Servicios utilizados&quot;">​</a></h2><ul><li><strong>Google Analytics 4</strong> para análisis de tráfico y uso.</li><li><strong>Google AdSense</strong> para entrega de anuncios y medición de campañas.</li></ul><h2 id="base-legal-y-consentimiento" tabindex="-1">Base legal y consentimiento <a class="header-anchor" href="#base-legal-y-consentimiento" aria-label="Permalink to &quot;Base legal y consentimiento&quot;">​</a></h2><ul><li>El almacenamiento técnico esencial se utiliza para el funcionamiento del sitio.</li><li>Las tecnologías de análisis y publicidad se habilitan solo después del consentimiento explícito a través del banner de cookies.</li><li>Puedes rechazar el consentimiento y seguir usando los documentos.</li></ul><h2 id="almacenamiento-de-consentimiento" tabindex="-1">Almacenamiento de consentimiento <a class="header-anchor" href="#almacenamiento-de-consentimiento" aria-label="Permalink to &quot;Almacenamiento de consentimiento&quot;">​</a></h2><ul><li>La elección de consentimiento se almacena localmente en el almacenamiento del navegador bajo una clave específica del sitio.</li><li>No se activa ningún análisis/seguimiento de anuncios antes de aceptar el consentimiento.</li></ul><h2 id="intercambio-de-datos" tabindex="-1">Intercambio de datos <a class="header-anchor" href="#intercambio-de-datos" aria-label="Permalink to &quot;Intercambio de datos&quot;">​</a></h2><ul><li>Google puede procesar los datos como procesador/controlador externo de acuerdo con los términos de servicio de Google.</li><li>No vendemos datos personales a través de este sitio web.</li></ul><h2 id="tus-controles" tabindex="-1">Tus controles <a class="header-anchor" href="#tus-controles" aria-label="Permalink to &quot;Tus controles&quot;">​</a></h2><ul><li>Aceptar o rechazar a través del banner de cookies.</li><li>Borre los datos del sitio del navegador (almacenamiento local/cookies) para restablecer su elección.</li><li>Utilice los controles de privacidad del navegador y la configuración de anuncios para restricciones adicionales.</li></ul><h2 id="actualizaciones-de-politicas" tabindex="-1">Actualizaciones de políticas <a class="header-anchor" href="#actualizaciones-de-politicas" aria-label="Permalink to &quot;Actualizaciones de políticas&quot;">​</a></h2><p>Esta política puede actualizarse cuando cambian las funciones de seguimiento o los requisitos legales.</p><h2 id="contacto" tabindex="-1">Contacto <a class="header-anchor" href="#contacto" aria-label="Permalink to &quot;Contacto&quot;">​</a></h2><p>Para solicitudes de privacidad, utilice los canales de soporte y contacto en el repositorio del proyecto: <a href="https://github.com/tsparticles/tsparticles" target="_blank" rel="noreferrer">https://github.com/tsparticles/tsparticles</a></p>',20)])])}const h=a(s,[["render",l]]);export{m as __pageData,h as default};
